async function splitAndSend(
  bot: WeChatBot,
  msg: IncomingMessage,
  text: string,
): Promise<void> {
  const chunks = buildChunks(text);
  for (const chunk of chunks) {
    await bot.reply(msg, chunk);
    if (chunks.length > 1) {
      await new Promise((r) => setTimeout(r, 150));
    }
  }
}

function buildChunks(text: string): string[] {
  // 不足阈值直接整体发送
  if (text.length <= SPLIT_MAX) return [text];

  const paragraphs = text.split(/\n\n+/);
  const result: string[] = [];
  let current = "";

  for (const para of paragraphs) {
    if (!para.trim()) continue;
    const next = current ? `${current}\n\n${para}` : para;

    if (next.length <= SPLIT_MAX) {
      // 小段继续累积，不拆
      current = next;
      continue;
    }

    // 加上这段就超了，先把已积累的推出去
    if (current) {
      result.push(current);
      current = "";
    }

    if (para.length <= SPLIT_MAX) {
      current = para;
      continue;
    }

    // 单段本身就超长，按句子边界拆，且尽量多塞
    const sentences = para.split(/(?<=[。！？…]+)/);
    for (const sentence of sentences) {
      if (!sentence.trim()) continue;
      if ((current + sentence).length <= SPLIT_MAX) {
        current += sentence;
      } else {
        if (current) result.push(current);
        current = sentence;
      }
    }
  }

  if (current) result.push(current);
  return result.length ? result : [text];
}

