import path from "node:path";
import { createBashTool, bashTool } from "@mariozechner/pi-coding-agent";
import type { AgentTool } from "@mariozechner/pi-agent-core";
import { wechatbotAgentWorkspace } from "../../lib/wechatbot-workspace";

export type SchoolIdentityContext = {
  role: "student" | "teacher";
  schoolId: string;
} | null;

const PROJECT_ROOT = path.resolve(process.cwd());

/** 所有用户数据目录的公共父目录，用于检测跨用户访问 */
const WECHATBOT_DATA_ROOT = path.resolve(PROJECT_ROOT, ".data", "wechatbot");

/** Skills 只读目录 */
export const PI_SKILLS_ROOT = path.resolve(PROJECT_ROOT, ".pi", "skills");

/** 绝对封锁的系统路径前缀 */
const BLOCKED_PREFIXES = [
  "/etc",
  "/root",
  "/sys",
  "/proc",
  "/dev",
  "/boot",
  "/private/etc", // macOS
];

const DEFAULT_SCHOOL_SERVER_URL = "http://127.0.0.1:3002";

function escapeRegExp(input: string): string {
  return input.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function schoolServerBaseUrls(): string[] {
  const envBase = process.env.SCHOOL_SERVER_URL?.trim();
  return [envBase, DEFAULT_SCHOOL_SERVER_URL]
    .filter((v): v is string => Boolean(v))
    .map((v) => v.replace(/\/$/, ""));
}

function commandTargetsSchoolServer(command: string): boolean {
  const bases = schoolServerBaseUrls();
  if (bases.some((base) => command.includes(base))) return true;
  return /\/api\/(students|teachers|courses|assignments|library|cafeteria|bus|campus-card|repair)\b/.test(command);
}

function extractSchoolApiPaths(command: string): string[] {
  const matches = command.match(/\/api\/[A-Za-z0-9_./?=&%-]*/g) ?? [];
  return matches.map((m) => m.split("?")[0].replace(/[)"'`;,]+$/g, ""));
}

/** 所有已登录用户均可访问的公共校园信息接口（不含个人数据） */
const PUBLIC_API_PATTERNS = [
  /^\/api\/library\/seats(\/availability)?$/,
  /^\/api\/library\/books(\/[^/]+)?$/,
  /^\/api\/cafeteria(\/[^/]+\/menu)?$/,
  /^\/api\/cafeteria\/menu\/today$/,
  /^\/api\/bus\/routes(\/[^/]+)?$/,
  /^\/api\/health$/,
];

function isAllowedSchoolApiPath(
  apiPath: string,
  identity: Exclude<SchoolIdentityContext, null>,
): boolean {
  // 公共接口：任何已绑定身份的用户均可访问
  if (PUBLIC_API_PATTERNS.some((p) => p.test(apiPath))) return true;

  const id = escapeRegExp(identity.schoolId);

  if (identity.role === "student") {
    return [
      // 教务
      new RegExp(`^/api/students/${id}$`),
      new RegExp(`^/api/students/${id}/courses$`),
      new RegExp(`^/api/assignments/unsubmitted/${id}$`),
      new RegExp(`^/api/assignments/student-submissions/${id}$`),
      // 图书馆预约（GET 按 studentId，POST/DELETE 服务端校验 body 中的 student_id）
      new RegExp(`^/api/library/reservations/${id}$`),
      /^\/api\/library\/reservations(\/[^/]+)?$/,
      // 校园卡（仅自己）
      new RegExp(`^/api/campus-card/${id}$`),
      // 报修（GET 按 studentId，POST 新增，PATCH 状态由服务端校验）
      new RegExp(`^/api/repair/${id}$`),
      /^\/api\/repair(\/[^/]+\/status)?$/,
    ].some((pattern) => pattern.test(apiPath));
  }

  return [
    new RegExp(`^/api/teachers/${id}$`),
    new RegExp(`^/api/courses/by-teacher/${id}$`),
  ].some((pattern) => pattern.test(apiPath));
}

function validateSchoolApiAccess(
  command: string,
  identity: SchoolIdentityContext,
): void {
  if (!commandTargetsSchoolServer(command)) return;
  const apiPaths = extractSchoolApiPaths(command);
  if (apiPaths.length === 0) return;

  if (!identity) {
    throw new Error("当前账号未绑定 student/teacher 身份，禁止访问 school-server /api。");
  }

  for (const apiPath of apiPaths) {
    if (!isAllowedSchoolApiPath(apiPath, identity)) {
      throw new Error(
        `越权教务查询已拦截：${apiPath}。当前绑定 ${identity.role}:${identity.schoolId}，仅允许访问本身份对应接口。`,
      );
    }
  }
}

function isUnder(parent: string, candidate: string): boolean {
  const rel = path.relative(parent, candidate);
  return !rel.startsWith("..") && !path.isAbsolute(rel);
}

/**
 * 从 shell 命令字符串中提取所有看起来像绝对路径的 token，
 * 并对每个路径执行访问策略检查：
 *
 *   - userRoot（.data/wechatbot/{userId}/）：读写均可
 *   - PI_SKILLS_ROOT（.pi/skills）：仅读；若命令含写操作则阻止
 *   - 其他路径：
 *       - BLOCKED_PREFIXES → 绝对封锁
 *       - 属于其他用户目录 → 封锁
 *       - 属于项目目录内其他位置 → 封锁
 *       - /usr、/bin、/tmp 等系统可执行路径 → 放行（仅作为命令本身）
 */
function validatePaths(
  command: string,
  userRoot: string,
  schoolIdentity: SchoolIdentityContext,
): void {
  // 提取绝对路径 token：以 / 开头、由合法路径字符组成
  const absPathRegex = /(?:^|[\s"'`|;&><(])(\/([\w.@%+\-]+(?:\/[\w.@%+\-]*)*)\/?)/g;
  let match: RegExpExecArray | null;

  // 检测是否有写操作（用于 .pi/skills 只读约束）
  const hasOutputRedirect = />{1,2}/.test(command);
  const hasWriteCommand =
    /\b(rm|rmdir|mv|cp|chmod|chown|touch|truncate|dd|tee|install)\b/.test(
      command,
    );

  while ((match = absPathRegex.exec(command)) !== null) {
    const rawPath = match[1];
    const resolved = path.resolve(rawPath);

    // 系统封锁路径
    if (
      BLOCKED_PREFIXES.some(
        (bp) => resolved === bp || resolved.startsWith(`${bp}/`),
      )
    ) {
      throw new Error(`禁止访问系统路径：${resolved}`);
    }

    const inUserRoot = isUnder(userRoot, resolved);
    const inPiSkills = isUnder(PI_SKILLS_ROOT, resolved);

    if (inUserRoot) continue; // 当前用户目录，完全放行

    if (inPiSkills) {
      // .pi/skills 只读：有写操作时阻止
      if (hasOutputRedirect || hasWriteCommand) {
        throw new Error(
          `.pi/skills 为只读目录，禁止写入操作（路径：${resolved}）`,
        );
      }
      continue;
    }

    // 其他用户的数据目录：封锁
    if (isUnder(WECHATBOT_DATA_ROOT, resolved)) {
      throw new Error(`禁止访问其他用户目录：${resolved}`);
    }

    // 项目目录内的其他路径：封锁
    if (isUnder(PROJECT_ROOT, resolved)) {
      throw new Error(
        `禁止访问项目路径 ${resolved}（仅允许 .data/wechatbot/<用户ID>/ 和 .pi/skills/）`,
