85	
86	/** 被截断后的 base64 为空，若仍以 image 块发给下游会触发 vision 侧解码失败 */
87	function isPlausibleImageBase64(data: string): boolean {
88	  return typeof data === "string" && data.trim().length >= 32;
89	}
90	
91	/** 将无效/被清空的图片块改为纯文本说明，避免上游收到 `data:...base64,` 空载荷 */
92	function sanitizePersistedMessages(messages: AgentMessage[]): AgentMessage[] {
93	  const stripImages = (
94	    blocks: (TextContent | ImageContent)[],
95	    emptyLabel: string,
96	  ): (TextContent | ImageContent)[] =>
97	    blocks.flatMap((block) => {
98	      if (block.type === "image" && !isPlausibleImageBase64(block.data)) {
99	        return [{ type: "text" as const, text: emptyLabel }];
100	      }
101	      return [block];
102	    });
103	
104	  return messages.map((m): AgentMessage => {
105	    if (m.role === "user") {
106	      if (typeof m.content === "string") return m;
107	      return {
108	        ...m,
109	        content: stripImages(
110	          m.content,
111	          "（历史图片未持久化，已省略；若需要请重新发送图片。）",
112	        ),
113	      };
114	    }
115	    if (m.role === "toolResult") {
116	      return {
117	        ...m,
118	        content: stripImages(m.content, "（工具返回中的图片已省略。）"),
119	      };
120	    }
121	    return m;
122	  });
123	}
124	
125	/** 持久化与内存中共用的最近消息条数上限（单条消息可为多轮中的一步） */
126	function maxStoredMessages(): number {
127	  const raw = process.env.AGENT_MAX_MESSAGES?.trim();
128	  const n = raw ? Number.parseInt(raw, 10) : 80;
129	  return Number.isFinite(n) && n >= 8 ? n : 80;
130	}
131	
132	function truncateMessagesTail(
133	  messages: AgentMessage[],
134	  max: number,
135	): AgentMessage[] {
136	  if (messages.length <= max) return messages;
137	  return messages.slice(-max);
138	}
139	
140	/**
141	 * 从最新 jsonl 装载；若条数超过上限则截断并立即写回磁盘，使增量 append 与文件一致。
142	 */
143	function loadPersistedMessagesFromJsonl(userId: string): AgentMessage[] {
144	  try {
145	    const raw = loadLatestSessionMessages(userId);
146	    const sanitized = sanitizePersistedMessages(raw);
147	    const persisted = truncateMessagesTail(sanitized, maxStoredMessages());
148	    const latest = getLatestSessionJsonlPath(userId);
149	    if (latest && persisted.length < raw.length) {
150	      persistMessagesToJsonl(latest, persisted, raw.length);
151	    }
152	    return persisted;
153	  } catch {
154	    console.warn(`[agent] user ${userId} 会话 jsonl 解析失败，已使用空上下文`);
155	    return [];
156	  }
157	}
158	
159	function guessImageMime(fileName?: string): string {
160	  if (!fileName) return "image/jpeg";
161	  const l = fileName.toLowerCase();
162	  if (l.endsWith(".png")) return "image/png";
163	  if (l.endsWith(".gif")) return "image/gif";
164	  if (l.endsWith(".webp")) return "image/webp";
165	  return "image/jpeg";
166	}
167	
168	/**
169	 * 部分 OpenAI 兼容服务（如 Qwen）对 `tools: []` 返回 400（「too short」）。
170	 * pi-ai 在「无工具」时会带上空数组；发出前去掉空 `tools` 字段。
171	 */
172	function omitEmptyToolsPayload(
173	  params: unknown,
174	  _model: Model<Api>,
175	): unknown | undefined {
176	  if (typeof params !== "object" || params === null) return undefined;
177	  const p = params as Record<string, unknown>;
178	  if (!Array.isArray(p.tools) || p.tools.length > 0) return undefined;
179	  const { tools: _t, ...rest } = p;
180	  return rest;
181	}
182	
183	export type AgentPromptOptions = {
184	  /** 当前微信对话对方 userId，用于工具里省略 target_user_id（bot.send） */
185	  defaultWechatTarget?: string;
186	  /** 当前入站微信消息；wechat_send 省略 target_user_id 时优先 bot.reply(msg, …) */
187	  wechatReplyMessage?: IncomingMessage;
188	  /**
189	   * 是否注册「创建定时任务」工具。定时任务到点执行时应为 false，避免执行中又创建任务。
190	   * @default true
191	   */
192	  cronTools?: boolean;
193	  /**
194	   * 传入当前用户的 WeChatBot 实例时，额外注册「发送网络资源 / 本地文件到微信」工具。
195	   */
196	  wechatBot?: WeChatBot;
197	};
198	
199	// ── 全局共享的 pi-coding-agent 基础设施 ──
200	
201	const authStorage = AuthStorage.create();
202	if (process.env.OPENAI_API_KEY) {
203	  authStorage.setRuntimeApiKey(
204	    model.provider,
205	    process.env.OPENAI_API_KEY,
206	  );
207	}
208	const modelRegistry = ModelRegistry.inMemory(authStorage);
209	const settingsManager = SettingsManager.inMemory({
210	  compaction: { ...DEFAULT_COMPACTION_SETTINGS },
211	  retry: { enabled: true, maxRetries: 2 },
212	});
213	
214	let _resourceLoader: DefaultResourceLoader | undefined;
215	
216	async function getResourceLoader(): Promise<DefaultResourceLoader> {
217	  if (!_resourceLoader) {
218	    const projectSkillRoot = path.resolve(process.cwd(), ".pi", "skills");
219	    _resourceLoader = new DefaultResourceLoader({
220	      systemPromptOverride: () => systemPrompt(),
221	      agentsFilesOverride: () => ({ agentsFiles: [] }),
222	      skillsOverride: (base) => ({
223	        skills: base.skills.filter((skill) => {
224	          const skillPath = path.resolve(skill.filePath);
225	          return (
226	            skillPath === projectSkillRoot ||
227	            skillPath.startsWith(`${projectSkillRoot}${path.sep}`)
228	          );
229	        }),
230	        diagnostics: base.diagnostics,
231	      }),
232	      promptsOverride: () => ({ prompts: [], diagnostics: [] }),
233	    });
234	  }
235	  await _resourceLoader.reload();
236	  return _resourceLoader;
237	}
238	
239	/**
240	 * pi `createAgentSession` 只用 `options.tools` 推导 **活跃工具名**，不会把自定义 AgentTool 挂进内置 registry；
241	 * 用户级 `read` 必须通过 `baseToolsOverride`（AgentSession 私有字段）注入。
242	 * Skill 文本由 `resourceLoader.reload()` + `buildSystemPrompt(customPrompt, skills)` 注入，与是否导入 `readTool` 常量无关。
243	 */
244	async function createUserSession(
245	  userId: string,
246	  messages?: AgentMessage[],
247	): Promise<AgentSession> {
248	  const resourceLoader = await getResourceLoader();
249	  const scopedRead = createUserScopedReadTool(userId);
250	  const scopedBash = createUserScopedBashTool(userId);
251	  const { session } = await createAgentSession({
252	    model,
253	    thinkingLevel: "off",
254	    /** 与 `allTools` 对齐，使 initialActiveToolNames = ["read","bash"]；真实实现见下方 `_baseToolsOverride` */
255	    tools: [readTool, bashToolPlaceholder],
256	    sessionManager: SessionManager.inMemory(),
257	    authStorage,
258	    modelRegistry,
259	    settingsManager,
260	    resourceLoader,
261	  });
262	  const patched = session as unknown as {
263	    _baseToolsOverride?: Record<string, AgentTool>;
264	    _buildRuntime: (opts?: {
265	      activeToolNames?: string[];
266	      includeAllExtensionTools?: boolean;
267	    }) => void;
268	  };
269	  patched._baseToolsOverride = {
270	    read: scopedRead as unknown as AgentTool,
271	    bash: scopedBash,
272	  };
273	  patched._buildRuntime({
274	    activeToolNames: session.getActiveToolNames(),
275	    includeAllExtensionTools: true,
276	  });
277	
278	  session.agent.onPayload = omitEmptyToolsPayload;
279	  // Trigger session_start so extensions (e.g. pi-mcp-adapter) initialize.
280	  await session.bindExtensions({});
281	  if (messages?.length) {
282	    session.agent.state.messages = messages;
283	  }
284	  return session;
285	}
286	
287	/** 超过该分钟数未调用 prompt 则回收内存中的 Session；0 表示不回收 */
288	function agentSessionIdleMinutes(): number {
289	  const raw = process.env.AGENT_SESSION_IDLE_MINUTES?.trim();
290	  if (raw === "0") return 0;
291	  const n = raw ? Number.parseFloat(raw) : 30;
292	  return Number.isFinite(n) && n >= 0 ? n : 30;
293	}
294	
295	type SessionFileState = { path: string; messageLinesOnDisk: number };
296	
297	export class AgentService {
298	  private sessions = new Map<string, AgentSession>();
299	  private chains = new Map<string, Promise<void>>();
300	  /** 最近一次 prompt 时间（仅内存中有 Session 的用户） */
301	  private lastActivity = new Map<string, number>();
302	  /** 当前内存 Session 与磁盘 jsonl 的增量同步（idle 回收后会清空，下次从最新文件重载） */
303	  private sessionFileState = new Map<string, SessionFileState>();
304	  /** school 业务单独封装，service 仅编排 */
305	  private schoolWorkflow = new SchoolWorkflowService();
306	  /** 已发送过欢迎语的联系人，key = `${botUserId}:${contactId}`，进程级去重 */
307	  private welcomedContacts = new Set<string>();
308	
309	  private touchActivity(userId: string): void {
310	    this.lastActivity.set(userId, Date.now());
311	  }
312	
313	  /** 在访问 Session 前惰性回收空闲实例（无全局 setInterval） */
314	  private async evictIdleSessionsIfStale(idleMs: number): Promise<void> {
315	    const now = Date.now();
316	    for (const [uid, session] of [...this.sessions.entries()]) {
317	      if (session.isStreaming) continue;
318	      const last = this.lastActivity.get(uid) ?? 0;
319	      if (now - last < idleMs) continue;
320	      try {
321	        await session.abort();
322	      } catch {
323	        /* ignore */
324	      }
325	      try {
326	        session.dispose();
327	      } catch {
328	        /* ignore */
329	      }
330	      this.sessions.delete(uid);
331	      this.lastActivity.delete(uid);
332	      this.sessionFileState.delete(uid);
333	      console.log(
334	        `[agent] 空闲回收 Session user ${uid}（>${Math.round(idleMs / 60_000)}min 无对话）`,
335	      );
336	    }
337	  }
338	
339	  async getOrCreate(userId: string): Promise<AgentSession> {
340	    const idleMin = agentSessionIdleMinutes();
341	    if (idleMin > 0) {
342	      await this.evictIdleSessionsIfStale(idleMin * 60_000);
343	    }
344	    let s = this.sessions.get(userId);
345	    if (!s) {
346	      const persisted = loadPersistedMessagesFromJsonl(userId);
347	      s = await createUserSession(userId, persisted);
348	      this.sessions.set(userId, s);
349	      const latest = getLatestSessionJsonlPath(userId);
350	      if (latest) {
351	        this.sessionFileState.set(userId, {
352	          path: latest,
353	          messageLinesOnDisk: persisted.length,
354	        });
355	      }
356	    }
357	    return s;
358	  }
359	
360	  async prompt(
361	    userId: string,
362	    text: string,
363	    images?: ImageContent[],
364	    opts?: AgentPromptOptions,
365	  ): Promise<string> {
366	    const school = await this.schoolWorkflow.preparePromptInput(userId, text);
367	    const session = await this.getOrCreate(userId);
368	    this.touchActivity(userId);
369	
370	    /** 勿整表覆盖：pi-mcp-adapter 等扩展会注册 `mcp`、内置 `read` 等 */
371	    const replaceableNames = new Set<string>([
372	      ...CRON_TOOL_NAMES,
373	      ...WECHAT_MEDIA_TOOL_NAMES,
374	      ...BASH_TOOL_NAMES,
375	    ]);
376	    const kept = session.agent.state.tools.filter(
377	      (t) => !replaceableNames.has(t.name),
378	    );
379	
380	    const cron =
381	      opts?.cronTools !== false
382	        ? buildCronTools(userId, {
383	          defaultWechatTarget: opts?.defaultWechatTarget,
384	        })
385	        : [];
386	    const media = opts?.wechatBot
387	      ? buildWechatMediaTools(userId, opts.wechatBot, {
388	        defaultWechatTarget: opts?.defaultWechatTarget,
389	        incomingWechatMessage: opts?.wechatReplyMessage,
390	      })
391	      : [];
392	    const bash = createUserScopedBashTool(userId, school.identity);
393	    session.agent.state.tools = [...kept, ...cron, ...media, bash];
394	
395	    if (images?.length) {
396	      await session.prompt(school.inputText || "请看图片。", { images });
397	    } else {
398	      await session.prompt(school.inputText);
399	    }
400	
401	    const reply = stripMarkdown(extractReply(session.messages) || "");
402	    const capped = truncateMessagesTail(session.messages, maxStoredMessages());
403	    if (capped.length !== session.messages.length) {
404	      session.agent.state.messages = capped;
405	    }
406	    await this.persistJsonl(userId, capped);
407	    return reply;
408	  }
409	
410	  private async persistJsonl(
411	    userId: string,
412	    capped: AgentMessage[],
413	  ): Promise<void> {
414	    try {
415	      let st = this.sessionFileState.get(userId);
416	      if (!st) {
417	        const p = createNewSessionJsonlFile(userId);
418	        const n = persistMessagesToJsonl(p, capped, 0);
419	        this.sessionFileState.set(userId, { path: p, messageLinesOnDisk: n });
420	        return;
421	      }
422	      const n = persistMessagesToJsonl(st.path, capped, st.messageLinesOnDisk);
423	      this.sessionFileState.set(userId, { path: st.path, messageLinesOnDisk: n });
424	    } catch (e) {
425	      console.error(`[agent] user ${userId} jsonl 保存失败`, e);
426	    }
427	  }
428	
429	  async reset(userId: string): Promise<void> {
430	    appendSessionEndMarker(userId, "user_new");
431	    createNewSessionJsonlFile(userId);
432	
433	    const s = this.sessions.get(userId);
434	    if (s) s.dispose();
435	    this.sessions.delete(userId);
436	    this.lastActivity.delete(userId);
437	    this.sessionFileState.delete(userId);
438	    this.schoolWorkflow.clearPending(userId);
439	  }
440	
441	  async getHistory(userId: string): Promise<AgentMessage[]> {
442	    const s = this.sessions.get(userId);
443	    if (s) return s.messages;
444	    return loadPersistedMessagesFromJsonl(userId);
445	  }
446	
447	  async remove(userId: string): Promise<void> {
448	    const s = this.sessions.get(userId);
449	    if (s) {
450	      await s.abort();
451	      s.dispose();
452	    }
453	    this.sessions.delete(userId);
454	    this.lastActivity.delete(userId);
455	    this.chains.delete(userId);
456	    this.sessionFileState.delete(userId);
457	    this.schoolWorkflow.clearAll(userId);
458	    removeAllSessionJsonlFiles(userId);
459	  }
460	
461	  /** 串行队列：同一用户的微信消息不并发 */
462	  enqueue(userId: string, task: () => Promise<void>): void {
463	    const prev = this.chains.get(userId) ?? Promise.resolve();
464	    const next = prev.then(task).catch((err) => {
465	      console.error(`[agent user:${userId}]`, err);
466	    });
