623	          },
624	        ],
625	      };
626	    }
627	
628	    try {
629	      const rel = await saveUserIncomingMediaFile(
630	        userId,
631	        media.data,
632	        media.fileName,
633	      );
634	      return {
635	        text: `用户发送了文件「${media.fileName ?? "附件"}」，已保存到用户目录（相对路径：${rel}）。可用 read 查看内容或根据上下文简要回应。`,
636	        pendingSubmissionFile: {
637	          relativePath: rel,
638	          fileName: media.fileName ?? "附件",
639	          receivedAt: Date.now(),
640	        },
641	      };
642	    } catch (e) {
643	      console.warn(`[agent user:${userId}] 保存微信附件失败`, e);
644	      return {
