651	export const agentService = new AgentService();
652	
653	/** 超过此长度才考虑拆分 */
654	const SPLIT_MAX = 300;
655	
656	async function splitAndSend(
657	  bot: WeChatBot,
658	  msg: IncomingMessage,
659	  text: string,
660	): Promise<void> {
661	  const chunks = buildChunks(text);
662	  for (const chunk of chunks) {
663	    await bot.reply(msg, chunk);
664	    if (chunks.length > 1) {
665	      await new Promise((r) => setTimeout(r, 150));
666	    }
667	  }
668	}
669	
670	/** 判断段落是否为列表项（数字序号、emoji序号、短横线等） */
671	function isListItem(para: string): boolean {
672	  const s = para.trim();
673	  return /^[\-\*•·]/.test(s) || /^\d+[.。、）)]\s/.test(s) || /^\d[^\S\n]/.test(s);
674	}
675	
676	function buildChunks(text: string): string[] {
677	  if (text.length <= SPLIT_MAX) return [text];
678	
679	  // 先将连续列表项合并为一个整体块，避免同组列表被拆散
680	  const rawParas = text.split(/\n\n+/).filter((p) => p.trim());
681	  const blocks: string[] = [];
682	  let i = 0;
683	  while (i < rawParas.length) {
684	    if (isListItem(rawParas[i]!)) {
685	      let block = rawParas[i]!;
686	      i++;
687	      while (i < rawParas.length && isListItem(rawParas[i]!)) {
688	        block += "\n\n" + rawParas[i];
689	        i++;
690	      }
691	      blocks.push(block);
692	    } else {
693	      blocks.push(rawParas[i]!);
694	      i++;
695	    }
696	  }
697	
698	  const result: string[] = [];
699	  let current = "";
700	
701	  for (const block of blocks) {
702	    const joined = current ? `${current}\n\n${block}` : block;
703	    if (joined.length <= SPLIT_MAX) { current = joined; continue; }
704	
705	    if (current) { result.push(current); current = ""; }
706	    if (block.length <= SPLIT_MAX) { current = block; continue; }
707	
708	    // 块本身超长：按行拆
709	    for (const line of block.split("\n")) {
710	      if (!line.trim()) continue;
711	      const lj = current ? `${current}\n${line}` : line;
712	      if (lj.length <= SPLIT_MAX) { current = lj; continue; }
713	      if (current) { result.push(current); current = ""; }
714	      if (line.length <= SPLIT_MAX) { current = line; continue; }
715	      // 单行超长：按句子末尾拆（最后手段）
716	      for (const seg of line.split(/(?<=[。！？；…]+)/)) {
717	        if (!seg.trim()) continue;
718	        const sj = current ? `${current}${seg}` : seg;
719	        if (sj.length <= SPLIT_MAX) { current = sj; }
720	        else { if (current) result.push(current); current = seg; }
721	      }
722	    }
723	  }
724	
725	  if (current.trim()) result.push(current.trim());
726	  return result.length ? result : [text];
727	}
