    const rows = await db
      .select({ contactUserId: wechatKnownContacts.contactUserId })
      .from(wechatKnownContacts)
      .where(eq(wechatKnownContacts.botUserId, botUserId));
    return rows.map((r) => r.contactUserId);
  } catch {
    return [];
  }
}

